SELECT strftime('%Y-%m', scan_date) as Month, COUNT(*) as NumberOfScans
FROM ct_scans
GROUP BY Month;

SELECT r.name, r.institution
FROM researchers r
INNER JOIN collaboration_platform cp ON r.researcher_id = cp.participant_id;

SELECT COUNT(scan_id)
FROM ct_scans
WHERE severe_hematoma_gt = 1 AND severe_hematoma_pred = 0;

SELECT COUNT(DISTINCT patient_id) AS patient_count
FROM scan_sessions
WHERE scan_date > DATE('now', '-6 months');

SELECT AVG(dice_coefficient) 
FROM ct_scans
WHERE severe_hematoma_gt = 1;

SELECT COUNT(*) AS TotalPatients
FROM patients
WHERE patient_id NOT IN (SELECT patient_id FROM treatment_plans);

SELECT COUNT(session_id) AS session_count, technician 
FROM scan_sessions 
GROUP BY technician;
